.."}]'),

('admin_2fa_code', 'account_security', 'Código 2FA Admin', 'Código de verificação em duas etapas para login admin', '🔐 Código de Verificação - Camaleão Admin', '<!DOCTYPE html><html><head><meta charset="UTF-8"></head><body style="margin:0;padding:0;font-family:''Segoe UI'',Tahoma,Geneva,Verdana,sans-serif;background-color:#f5f5f5;"><table width="100%" cellpadding="0" cellspacing="0" style="background-color:#f5f5f5;padding:40px 20px;"><tr><td align="center"><table width="600" cellpadding="0" cellspacing="0" style="background-color:#ffffff;border-radius:16px;overflow:hidden;box-shadow:0 4px 20px rgba(0,0,0,0.1);"><tr><td style="background:linear-gradient(135deg,#820AD1 0%,#6B08A8 100%);padding:40px;text-align:center;"><h1 style="color:white;margin:0 0 8px 0;font-size:28px;">🔐 Código de Verificação</h1><p style="color:rgba(255,255,255,0.9);margin:0;font-size:16px;">Área Administrativa</p></td></tr><tr><td style="padding:40px;text-align:center;"><p style="color:#666;line-height:1.6;">Use o código abaixo para acessar o painel administrativo:</p><div style="background:#f8f0ff;border:2px solid #820AD1;border-radius:12px;padding:20px;margin:20px 0;"><span style="font-size:36px;font-weight:700;letter-spacing:8px;color:#820AD1;">{{code}}</span></div><p style="color:#999;font-size:14px;">Este código expira em {{expiry_minutes}} minutos.</p></td></tr><tr><td style="background:#820AD1;padding:30px;text-align:center;"><p style="color:white;margin:0;font-size:16px;font-weight:600;">Camaleão Ecoturismo</p></td></tr></table></td></tr></table></body></html>', '[{"key": "code", "label": "Código 2FA", "example": "123456"}, {"key": "expiry_minutes", "label": "Minutos até expirar", "example": "10"}]'),

('account_created', 'account_security', 'Conta Criada', 'Boas-vindas ao criar conta no portal do cliente', 'Bem-vindo(a) à Camaleão Ecoturismo! 🦎', '<!DOCTYPE html><html><head><meta charset="UTF-8"></head><body style="margin:0;padding:0;font-family:''Segoe UI'',Tahoma,Geneva,Verdana,sans-serif;background-color:#f5f5f5;"><table width="100%" cellpadding="0" cellspacing="0" style="background-color:#f5f5f5;padding:40px 20px;"><tr><td align="center"><table width="600" cellpadding="0" cellspacing="0" style="background-color:#ffffff;border-radius:16px;overflow:hidden;box-shadow:0 4px 20px rgba(0,0,0,0.1);"><tr><td style="background:linear-gradient(135deg,#820AD1 0%,#6B08A8 100%);padding:40px;text-align:center;"><h1 style="color:white;margin:0 0 8px 0;font-size:28px;">🦎 Bem-vindo(a)!</h1><p style="color:rgba(255,255,255,0.9);margin:0;font-size:16px;">Camaleão Ecoturismo</p></td></tr><tr><td style="padding:40px;"><h2 style="color:#333;margin:0 0 16px 0;">Olá, {{nome}}!</h2><p style="color:#666;line-height:1.6;">Sua conta foi criada com sucesso! Agora você pode:</p><ul style="color:#666;line-height:1.8;"><li>Acompanhar suas reservas</li><li>Acumular pontos de fidelidade</li><li>Conquistar selos exclusivos</li><li>Receber ofertas especiais</li></ul><div style="text-align:center;margin:30px 0;"><a href="{{portal_link}}" style="background:#820AD1;color:white;padding:16px 32px;text-decoration:none;border-radius:8px;font-weight:600;display:inline-block;">Acessar Minha Conta</a></div></td></tr><tr><td style="background:#820AD1;padding:30px;text-align:center;"><p style="color:white;margin:0;font-size:16px;font-weight:600;">Camaleão Ecoturismo</p><p style="color:rgba(255,255,255,0.7);margin:8px 0 0 0;font-size:13px;">Transformando cada viagem em uma aventura inesquecível</p></td></tr></table></td></tr></table></body></html>', '[{"key": "nome", "label": "Nome do cliente", "example": "Maria Santos"}, {"key": "portal_link", "label": "Link do portal", "example": "https://..."}]'),

