('refund_full', 'cancellation_refund', 'Reembolso Total', 'Confirmação de reembolso total', '💰 Reembolso Processado - {{tour_nome}}', '<!DOCTYPE html><html><head><meta charset="UTF-8"></head><body style="margin:0;padding:0;font-family:''Segoe UI'',Tahoma,Geneva,Verdana,sans-serif;background-color:#f5f5f5;"><table width="100%" cellpadding="0" cellspacing="0" style="background-color:#f5f5f5;padding:40px 20px;"><tr><td align="center"><table width="600" cellpadding="0" cellspacing="0" style="background-color:#ffffff;border-radius:16px;overflow:hidden;box-shadow:0 4px 20px rgba(0,0,0,0.1);"><tr><td style="background:linear-gradient(135deg,#10B981 0%,#059669 100%);padding:40px;text-align:center;"><h1 style="color:white;margin:0 0 8px 0;font-size:28px;">💰 Reembolso Processado</h1><p style="color:rgba(255,255,255,0.9);margin:0;font-size:16px;">Reembolso Total</p></td></tr><tr><td style="padding:40px;"><h2 style="color:#333;margin:0 0 16px 0;">Olá, {{nome}}!</h2><p style="color:#666;line-height:1.6;">Seu reembolso foi processado com sucesso!</p><div style="background:#ecfdf5;border-left:4px solid #10B981;padding:15px;margin:20px 0;"><p style="margin:0;color:#065f46;font-weight:600;font-size:18px;">R$ {{valor_reembolso}}</p><p style="margin:8px 0 0 0;color:#065f46;">Prazo: até 7 dias úteis</p></div><p style="color:#666;line-height:1.6;">O valor será creditado na mesma forma de pagamento utilizada na compra.</p></td></tr><tr><td style="background:#820AD1;padding:30px;text-align:center;"><p style="color:white;margin:0;font-size:16px;font-weight:600;">Camaleão Ecoturismo</p></td></tr></table></td></tr></table></body></html>', '[{"key": "nome", "label": "Nome do cliente", "example": "João Silva"}, {"key": "tour_nome", "label": "Nome do passeio", "example": "Trilha das Cachoeiras"}, {"key": "valor_reembolso", "label": "Valor do reembolso", "example": "350,00"}]'),

